import { createFeatureSelector, createSelector } from '@ngrx/store';
import { settingsFeatureKey } from './settings.reducer';
export const getSettingsState = createFeatureSelector(settingsFeatureKey);
export const getSettingsIsLoaded = createSelector(getSettingsState, state => state.isLoaded);
export const getSettingsError = createSelector(getSettingsState, state => state.error);
export const getAllSettings = createSelector(getSettingsState, state => state.settings);
